import{_ as a,o as t,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Team (New)","description":"","frontmatter":{"title":"Team (New)","slug":"team-new"},"headers":[],"relativePath":"account-hub/team-new.md","filePath":"account-hub/team-new.md"}'),s={name:"account-hub/team-new.md"};function n(i,e,m,l,c,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Team tab of the Security &amp; Access page is where you manage team member access and permissions for your Branch account. Use this page to add team members, assign roles, and control who has access to your Branch data and settings.</p><p>You can access this page by navigating to <strong>Configuration &gt; Security &amp; Access &gt;</strong> <a href="https://branchdocs.app.link/security-access-team" target="_blank" rel="noreferrer"><strong>Team</strong></a> in Branch.</p><div class="danger custom-block"><p class="custom-block-title">Don&#39;t see this page yet?</p><p>The Security &amp; Access page is part of the <a href="./new-branch-overview.html">new Branch</a> experience. This page is being rolled out to customers in phases through 2026. While you&#39;re waiting for access, you can explore this article to familiarize yourself with the new functionality.</p></div><h2 id="manage-team-members" tabindex="-1">Manage team members <a class="header-anchor" href="#manage-team-members" aria-label="Permalink to &quot;Manage team members&quot;">​</a></h2><p>The team member table shows each user&#39;s name, email address, assigned role, and current status.</p><h3 id="add-team-members" tabindex="-1">Add team members <a class="header-anchor" href="#add-team-members" aria-label="Permalink to &quot;Add team members&quot;">​</a></h3><p>To add a new team member to your Branch account:</p><ol><li>Navigate to <strong>Configuration &gt; Security &amp; Access &gt;</strong> <a href="https://branchdocs.app.link/security-access-team" target="_blank" rel="noreferrer"><strong>Team</strong></a>.</li><li>Select the <strong>Add team member</strong> button in the top right corner.</li><li>Enter the new team member&#39;s email address.</li><li>Enter their first name and last name.</li><li>Select the appropriate <a href="./default-access-levels-users-roles-permissions.html">access level</a> from the <strong>Access level</strong> dropdown.</li><li>If needed, enable <strong>Export access</strong> to allow the user to export sensitive data from pages they can view.</li><li>Configure granular <strong>Permissions</strong> by selecting <strong>View access</strong> and/or <strong>Edit access</strong> for specific features.</li><li>Select <strong>Invite</strong> to send an invitation email to the new team member.</li></ol><p>The new team member will receive an email invitation to join your Branch account. Once they&#39;ve accepted, their status in the team member table will change to <strong>Joined</strong>.</p><h3 id="search-team-members" tabindex="-1">Search team members <a class="header-anchor" href="#search-team-members" aria-label="Permalink to &quot;Search team members&quot;">​</a></h3><p>Use the search bar at the top of the team member table to quickly find specific team members. This is particularly useful for organizations with large teams.</p><h3 id="edit-team-members" tabindex="-1">Edit team members <a class="header-anchor" href="#edit-team-members" aria-label="Permalink to &quot;Edit team members&quot;">​</a></h3><p>To modify a team member&#39;s role or information:</p><ol><li>Select the <strong>three-dot menu icon</strong> on the right side of the team member&#39;s row.</li><li>Select <strong>Edit</strong> from the dropdown menu.</li><li>Update the team member&#39;s role or other information as needed.</li><li>Select <strong>Save</strong> to apply your changes.</li></ol><h3 id="remove-team-members" tabindex="-1">Remove team members <a class="header-anchor" href="#remove-team-members" aria-label="Permalink to &quot;Remove team members&quot;">​</a></h3><p>To remove a team member from your Branch account:</p><ol><li>Select the <strong>three-dot menu icon</strong> on the right side of the team member&#39;s row.</li><li>Select <strong>Delete user</strong> from the dropdown menu.</li><li>Confirm the deletion when prompted.</li></ol><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Removing a team member immediately revokes their access to your Branch account. They&#39;ll no longer be able to log in or access any Branch data or settings. This action can&#39;t be undone, but you can re-invite the user if needed.</p></div><h2 id="team-member-roles" tabindex="-1">Team member roles <a class="header-anchor" href="#team-member-roles" aria-label="Permalink to &quot;Team member roles&quot;">​</a></h2><p>Branch provides four role types to control team member access and permissions: Admin, Team Member, Limited Read, and Full Read. Each role grants different levels of access to your Branch account. To learn more about each role, visit our dedicated <a href="./default-access-levels-users-roles-permissions.html">guide</a>.</p><h2 id="best-practices" tabindex="-1">Best practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best practices&quot;">​</a></h2><p>Follow these best practices when managing your Branch team:</p><ul><li><strong>Follow the principle of least privilege</strong>: Assign team members the minimum role necessary to perform their job functions. Use read-only roles when possible.</li><li><strong>Review team access regularly</strong>: Periodically audit your team member list to ensure only current employees have access and that role assignments are still appropriate.</li><li><strong>Remove access promptly</strong>: When team members leave your organization or change roles, remove or update their Branch access immediately.</li></ul>',24)])])}const p=a(s,[["render",n]]);export{u as __pageData,p as default};
